#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        char s[300005]; scanf("%s",s);
        int cnt10=0;
        for(int i=0;i<N;i+=2){
            if(s[i]=='1' && s[i+1]=='0') cnt10++;
        }
        int ans = N - 2*cnt10 + (cnt10>0);
        printf("%d\n",ans);
    }
    return 0;
}

